CREATE TABLE data_domain_to_data_type_classification
(
	id serial,
	data_domain_id integer NOT NULL,
	data_type_classification_id integer DEFAULT NULL,
	CONSTRAINT pk_data_domain_to_data_type_classification PRIMARY KEY (id)
	, CONSTRAINT fk_data_domain_to_data_type_classification_to_data_domain FOREIGN KEY (data_domain_id) REFERENCES data_domains (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE CASCADE
	, CONSTRAINT fk_data_domain_to_data_type_classification_to_data_type_classification FOREIGN KEY (data_type_classification_id) REFERENCES data_type_classifications (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE CASCADE
);
CREATE INDEX i_data_domain_to_data_type_classification_data_domain ON data_domain_to_data_type_classification (data_domain_id);
CREATE INDEX i_data_domain_to_data_type_classification_data_type_classification ON data_domain_to_data_type_classification (data_type_classification_id);
